  "verses": [
    {
      "n": 30,
      "column": "left",
      "text": "Un Mibsams/ Mismus/ un Dumus/ Musus/ Adads un Temus.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Jeturs/ Nawis/ un Kedmus. Schee bija Ismaëka Behrni.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Un Keturas/ Abbrääma seekas Seewas Behrni/ ta dsein- deja Sinramu/ un Jeksanu/ un Medanu/ un Midijanu/ un Jes-baku/ un Suu. Un Joksana Behrni bija: Sebus un Dedans.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Un Midtjana Behrni bija: Eepus/ un Eewers/ un Anoks/ un Abtdus un Eldaïs. Schee wiſi bija Keturas Behrni.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Un Abbrääms dsemdinaja Ibsääku: Ibsääka Beheni bija Eesaws un Israëls.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Eesawa Behrni bija: Eeliwas/ Reguëls/ Jeïs un Jaëlams/ un Korns.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Eetiwasja Behrni bija: Teemans/ un Omars/ Zepus un Gaätans/ Kenas/ un Tinnus/ un Amaleks.\n"
    },
    {
      "n": 37,
      "column": "left",
      "text": "Reguëta Behrni bija: Naäts/ Serus/ Sammus un Misus.\n"
    },
    {
      "n": 38,
      "column": "left",
      "text": "Un Seira Behrni bija: Lotans un Sobals/ un Zibeans/ un Anus/ un Disons/ un Ezers/ un Disans.\n"
    },
    {
      "n": 39,
      "column": "left",
      "text": "Un Lotana Behrni bija: Orus/ un Omains/ un Lotana Mahsa bija Timna.\n"
    },
    {
      "n": 40,
      "column": "left",
      "text": "Sobala Behrni bija: Alijans/ un Manaäts/ un Ebats/ Sewus un Onams. Un Zibeana Behrni bija: Ajus un Anus.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Anus Behrnt bija: Di- sons. Un Disona Behrni bija/ Aimrams/ un Eebans/ un Je-trans/ un Krans.\n"
    },
    {
      "n": 42,
      "column": "right",
      "text": "Ezera Behrni bija: Bi-lans/ un Snëwans/ Jaëkans. Disana Behrni bija uz un Arans.\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Un schee irr tee Kehuini/ kas Eedoma Semmê waldijscht/ pirins Kehnini pahr Israëka Behrneem waldija. Belus/ Beora Dehls/ un winna Pils-fahta Wahrdg bija Dinaba.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Un Belus nomirre/ un winna Weeta tappe par Kehni-nu Jobabs Sera Dehls no Bazras.\n"
    },
    {
      "n": 45,
      "column": "right",
      "text": "Un Jobabs nomirre / un Usams no tahs Temaniteru Semmes tappe par Kehninu winna Weetâ.\n"
    },
    {
      "n": 46,
      "column": "right",
      "text": "Un Usams nomirre / un Adads Bedada Dehls tappe par Kehninu winna Weetâ/ kas tohs Midijaniterus Moaba Lauka kawe/ un winna Pilssahta Wahrdg bija Awits.\n"
    },
    {
      "n": 47,
      "column": "right",
      "text": "Un Adads nomirre / un Samlus no Masrekas tappe par Kehninu winna Weetâ.\n"
    },
    {
      "n": 48,
      "column": "right",
      "text": "Un kad Samlus nomir-re/ tad tappe Sauls no Reko-bota pre tahs Uppes par Kehni-nu winna Weetâ.\n"
    },
    {
      "n": 49,
      "column": "right",
      "text": "Un kad Sauls nomirre/ tad tappe Baäl-Anans Akhora Dehls par Kehninu winna Weetâ.\n"
    },
    {
      "n": 50,
      "column": "right",
      "text": "Un kad Baäl-Anans no-mirre/ tad tappe Adads par Keh-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
